import{_ as a,o as e,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Google SKAdNetwork","description":"","frontmatter":{"title":"Google SKAdNetwork","slug":"google-skadnetwork"},"headers":[],"relativePath":"marketer-hub/google-skadnetwork.md","filePath":"marketer-hub/google-skadnetwork.md"}'),d={name:"marketer-hub/google-skadnetwork.md"};function n(i,t,s,l,h,p){return e(),o("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The introduction of iOS 14.5 came with the rise of SKAdNetwork (SKAN) which had industry-wide impacts on the mobile measurement and attribution ecosystem. As such, Google will work differently from most non-self-attribution networks when it comes to SKAdNetwork campaigns.</p><p>Google will not be forwarding individual SKAdNetwork Postbacks to Branch. However, aggregate SKAN data will be passed back via Google&#39;s Ads API. In this flow, Google collects individual SKAN postbacks, cryptographically validates them internally, and then provides only pre-generated results to Branch via an API endpoint. Additionally, data shared via API may not include all data dimensions reflected in the SKAdNetwork postbacks.</p><h2 id="google-skan-support" tabindex="-1">Google SKAN Support <a class="header-anchor" href="#google-skan-support" aria-label="Permalink to &quot;Google SKAN Support&quot;">​</a></h2><h3 id="supported-campaigns" tabindex="-1">Supported Campaigns <a class="header-anchor" href="#supported-campaigns" aria-label="Permalink to &quot;Supported Campaigns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Google Campaign Type</th><th>SKAdNetwork Support for Branch</th></tr></thead><tbody><tr><td>App Campaigns</td><td>✅ Provides aggregate SKAN data to Branch via API</td></tr><tr><td>App campaigns for engagement</td><td>❌ Does not support SKAN</td></tr><tr><td><em><strong>All others</strong></em></td><td>❌ Does not support SKAN</td></tr></tbody></table><h3 id="supported-data-dimensions-via-api" tabindex="-1">Supported Data Dimensions via API <a class="header-anchor" href="#supported-data-dimensions-via-api" aria-label="Permalink to &quot;Supported Data Dimensions via API&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Data Support</th></tr></thead><tbody><tr><td>Download/Install</td><td>✅</td></tr><tr><td>Reinstall</td><td>✅</td></tr><tr><td>Conversion Value</td><td>✅</td></tr><tr><td>Campaign Name</td><td>✅</td></tr><tr><td>Campaign ID</td><td>✅</td></tr><tr><td>SKAdNetwork Campaign ID</td><td>❌</td></tr><tr><td>Postback Sequence Index (SKAN 4.0+)</td><td>✅</td></tr><tr><td>Coarse Conversion Value (SKAN 4.0+)</td><td>✅</td></tr></tbody></table><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>Because Google is utilizing the existing Google API to send SKAN data, the implementation is to activate Google Ads as a self-attribution ad network. Please follow the comprehensive guide on <a href="./enable-google-app-campaigns.html">enabling Google Ads with Branch</a>.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You must add all the accounts that you want to receive SKAN data for. If you only add one, you will only receive SKAN data for that account.</p></div><h2 id="skan-reports" tabindex="-1">SKAN Reports <a class="header-anchor" href="#skan-reports" aria-label="Permalink to &quot;SKAN Reports&quot;">​</a></h2><p>You can use the Branch Dashboard to view reporting on all of your SKAN-related campaigns. If you want to look at Google SKAN data, you can apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad network</td><td>equals</td><td><code>a_google_adwords</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Additional resources</p><p>You can see more ways to view SKAN Reports with our <a href="./skadnetwork-dashboard-reports.html">guide</a>.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h4 id="branch-dashboard-data-sync" tabindex="-1">Branch Dashboard Data Sync <a class="header-anchor" href="#branch-dashboard-data-sync" aria-label="Permalink to &quot;Branch Dashboard Data Sync&quot;">​</a></h4><p>If you feel the data that you see in the Branch Dashboard is not correct, we recommend waiting 24-48 hours after implementation. It has a similar delay to cost data displayed on traditional SAN app install campaigns. Google’s conversion date is by <strong>ad interaction date (click)</strong>, they have a system that matches an Apple postback to an ad interaction.</p>',18)])])}const m=a(d,[["render",n]]);export{u as __pageData,m as default};
